// ============================================================
// EXTRAI DADOS E SALVA - roda para TODAS as mensagens do grupo
// (independente de mencionar o bot)
// Captura: texto, mídia, mensagens citadas (quoted)
// ============================================================
const body = $input.first().json;
const b = body.body || {};

// Green API
const gMsg = b.messageData || {};
const gText = gMsg.textMessageData?.textMessage || gMsg.extendedTextMessageData?.text || '';
const gSender = b.senderData?.senderName || b.senderData?.senderContactName || '';
const gMsgId = b.idMessage || gMsg.idMessage || '';
const gChat = b.senderData?.chatId || '';

// Evolution API
const eData = b.data || b || {};
const eMsg = eData.message || {};
const eText = eMsg.conversation || eMsg.extendedTextMessage?.text || eMsg.imageMessage?.caption || eMsg.videoMessage?.caption || '';
const eSender = eData.pushName || '';
const eMsgId = eData.key?.id || '';
const eChat = eData.key?.remoteJid || '';

// Detecta tipo de mídia quando não tem texto
let mediaTag = '';
if (!eText && !gText) {
  if (eMsg.imageMessage) mediaTag = '[imagem]';
  else if (eMsg.videoMessage) mediaTag = '[vídeo]';
  else if (eMsg.audioMessage || eMsg.pttMessage) mediaTag = '[áudio]';
  else if (eMsg.stickerMessage) mediaTag = '[figurinha]';
  else if (eMsg.contactMessage || eMsg.contactsArrayMessage) mediaTag = '[contato]';
  else if (eMsg.locationMessage || eMsg.liveLocationMessage) mediaTag = '[localização]';
  else if (eMsg.documentMessage) mediaTag = '[documento: ' + (eMsg.documentMessage.fileName || 'arquivo') + ']';
  else if (eMsg.reactionMessage) mediaTag = '[reação: ' + (eMsg.reactionMessage.text || '') + ']';
}

// Captura contexto de mensagem citada (quoted/reply)
let quotedContext = '';
const ctxInfo = eMsg.extendedTextMessage?.contextInfo || eMsg.imageMessage?.contextInfo || eMsg.videoMessage?.contextInfo || eMsg.audioMessage?.contextInfo || {};
const quotedMsg = ctxInfo.quotedMessage;
if (quotedMsg) {
  const qText = quotedMsg.conversation || quotedMsg.extendedTextMessage?.text || quotedMsg.imageMessage?.caption || '';
  if (qText) {
    quotedContext = ' [em resposta a: "' + qText.substring(0, 300) + '"]';
  }
}

const textMessage = gText || eText || mediaTag;
const sender = gSender || eSender || 'Alguém';
const messageId = gMsgId || eMsgId || ('tmp_' + Date.now());
const chatId = gChat || eChat;

// Só ignora se não tiver nenhum conteúdo identificável
if (!textMessage) {
  return [];
}

// Monta mensagem final com contexto de citação
const finalMessage = textMessage + quotedContext;

// Detecta tipo de atendimento automaticamente
const msgLower = finalMessage.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
let tipoAtendimento = null;

// Palavras que indicam RESOLUÇÃO (especialmente com mensagem citada)
const resolucaoKeys = ['resolvido', 'finalizado', 'concluido', 'pronto', 'feito', 'normalizado', 'restabelecido', 'ok feito', 'ja foi'];
const isResolucao = resolucaoKeys.some(k => msgLower.includes(k));

// Palavras que indicam SOLICITAÇÃO de serviço
const solicitacaoKeys = ['sem internet', 'sem sinal', 'sem conexao', 'caiu a internet', 'caiu o sinal', 'esta sem', 'ta sem', 'cliente sem', 'problema', 'rompimento', 'sem fibra', 'onu apagada', 'onu vermelha', 'luz vermelha', 'instalar', 'instalacao', 'retirada', 'cancelamento', 'mudanca de endereco', 'upgrade', 'downgrade'];
const isSolicitacao = solicitacaoKeys.some(k => msgLower.includes(k));

if (isResolucao) {
  tipoAtendimento = 'resolucao';
} else if (isSolicitacao) {
  tipoAtendimento = 'solicitacao';
}

return [{
  json: {
    dbRemetente: sender,
    dbMensagem: finalMessage,
    messageId,
    chatId,
    tipoAtendimento
  }
}];

// ============================================================
// VERIFICA MENÇÃO - só continua se o bot foi mencionado
// ============================================================
const body = $('Webhook').first().json;
const b = body.body || {};

// Green API
const gMsg = b.messageData || {};
const gText = gMsg.textMessageData?.textMessage || gMsg.extendedTextMessageData?.text || '';
const gChat = b.senderData?.chatId || '';

// Evolution API
const eData = b.data || b || {};
const eMsg = eData.message || {};
const eText = eMsg.conversation || eMsg.extendedTextMessage?.text || '';
const eChat = eData.key?.remoteJid || '';

const textMessage = gText || eText;
const chatId = gChat || eChat;
// Ignora mensagens antigas (histórico de sincronização da Evolution API)
const msgTimestamp = eData.messageTimestamp || 0;
const nowTimestamp = Math.floor(Date.now() / 1000);
if (msgTimestamp && (nowTimestamp - msgTimestamp) > 120) {
  return []; // mensagem com mais de 2 minutos, ignora
}

// Verifica menção de forma precisa (não usa fullContent para evitar falsos positivos)
const botNumbers = ['554396543242', '235437994062039'];

// 1. Checa mentionedJid (Evolution API)
const mentionedJids = eMsg.extendedTextMessage?.contextInfo?.mentionedJid ||
  eMsg.imageMessage?.contextInfo?.mentionedJid || [];
const isMentionedJid = mentionedJids.some(jid => botNumbers.some(n => jid.includes(n)));

// 2. Checa @menção no texto
const isMentionedText = botNumbers.some(n => textMessage.includes('@' + n) || textMessage.includes('@' + n.slice(2)));

// 3. Checa se é mensagem direta (não grupo)
const isDirectMessage = chatId && !chatId.includes('@g.us');

if (!isMentionedJid && !isMentionedText && !isDirectMessage) {
  return [];
}

const txtLower = textMessage.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

// Detecta tipo de relatório
const isReportMensal = txtLower.includes('mensal') || txtLower.includes('mes') || txtLower.includes('mês');
const isReportSemanal = !isReportMensal && (txtLower.includes('semanal') || txtLower.includes('semana'));
const isReport = txtLower.includes('relatorio') || txtLower.includes('resumo');
const reportType = isReportMensal ? 'mensal' : isReportSemanal ? 'semanal' : 'diario';

const isTraining = txtLower.startsWith('claude aprenda') || txtLower.startsWith('claude correcao') ||
  textMessage.toLowerCase().includes('claude aprenda') || textMessage.toLowerCase().includes('claude correcao');

return [{ json: { chatId, textMessage, isReport, isTraining, reportType } }];

// ============================================================
// MONTA PROMPT - MÁXIMA PERFORMANCE + LEIA SEMPRE
// ============================================================

// HISTORICO REDIS
let redisHistory = [];
try {
  const rv = $('Busca Histórico Redis').first().json?.propertyName || $('Busca Histórico Redis').first().json?.value;
  if (rv) redisHistory = JSON.parse(rv);
} catch(e) {}

// CHAMADOS
let chamadosContext = '';
try {
  const cv = $('Busca Chamados Redis').first().json?.propertyName || $('Busca Chamados Redis').first().json?.value;
  if (cv) {
    const chamadosData = JSON.parse(cv);
    if (chamadosData.ai_context) {
      chamadosContext = '\n\n⚠️ CHAMADOS DO SISTEMA (ATUALIZADOS AGORA - DADOS OFICIAIS):\n'
        + 'REGRAS OBRIGATORIAS SOBRE CHAMADOS:\n'
        + '1. Os numeros no resumo abaixo sao EXATOS e PRE-CALCULADOS. NUNCA reconte.\n'
        + '2. Confie no resumo. NAO diga que precisa acessar outro sistema.\n\n'
        + chamadosData.ai_context.substring(0, 30000);
    }
  }
} catch(e) {}

// REMETENTE
let remetente = '';
try { remetente = $('Extrai Dados Mensagem').first().json?.dbRemetente || ''; } catch(e) {}

// 1. REGRAS
let rules = '';
try {
  const rulesData = $('Busca Regras').all().map(r => r.json.regra).filter(Boolean);
  rules = [...new Set(rulesData)].slice(0, 30).join('\n- ');
} catch(e) {}
const rulesPrompt = rules ? '\n\n⚠️ REGRAS ADICIONAIS DE TREINAMENTO (Siga Rigorosamente):\n- ' + rules : '';

// 2. SYSTEM PROMPT
let systemPromptTemplate = null;
try {
  const spRows = $('Busca System Prompt').all().map(d => d.json);
  for (const r of spRows) {
    if (r.chave === 'system_prompt' && r.valor) { systemPromptTemplate = r.valor; break; }
  }
  if (systemPromptTemplate && systemPromptTemplate.length > 50000) {
    systemPromptTemplate = systemPromptTemplate.substring(0, 50000) + '\n[...truncado...]';
  }
} catch(e) {}

// 3. HISTÓRICO DO GRUPO
let historicoSection = '';
try {
  const histRows = $('Busca Histórico 10').all().map(e => e.json);
  const histMap = new Map();
  for (const h of histRows) { if (h.id) histMap.set(h.id, h); }
  const uniqueHist = Array.from(histMap.values()).sort((a,b) => a.id - b.id).slice(-10);
  let historico = '';
  for (const msg of uniqueHist) {
    let hora = '??:??';
    try {
      const d = new Date(new Date(msg.data_hora).getTime() - 3 * 60 * 60 * 1000);
      hora = d.toISOString().substring(11, 16);
    } catch(e) {}
    historico += `[${hora}] ${msg.remetente}: ${(msg.mensagem || '').substring(0, 400)}\n`;
  }
  if (historico) historicoSection = `\n\nÚLTIMAS MENSAGENS DO GRUPO:\n${historico}`;
} catch(e) {}

// 4. POPs — COM SEPARAÇÃO DE "LEIA SEMPRE"
const allPopsInputs = $("Busca POPs").all().map(i => i.json).filter(p => p.titulo);
const popMap = new Map();
for (const p of allPopsInputs) {
  if (p.conteudo || !popMap.has(p.titulo)) popMap.set(p.titulo, p);
}
const uniquePops = Array.from(popMap.values());

let clientesContent = '';
const allNonClientTitles = [];
const relevantNonClientPops = [];
let leiasSemprePops = [];

for (const pop of uniquePops) {
  const cat = (pop.categoria || '').toLowerCase();
  const titulo = (pop.titulo || '').toLowerCase();
  const isClientDB = cat.includes('cliente') || cat.includes('banco') || cat.includes('base') || cat.includes('crm');
  const isObrigatorio = titulo.includes('leia sempre');

  if (isClientDB) {
    if (pop.conteudo) clientesContent += pop.conteudo + '\n';
  } else if (isObrigatorio) {
    if (pop.conteudo) leiasSemprePops.push(pop);
    allNonClientTitles.push(pop);
  } else {
    allNonClientTitles.push(pop);
    if (pop.conteudo) relevantNonClientPops.push(pop);
  }
}

// 5. COLABORADORES
let colaboradoresArray = [];
try {
  const colabRows = $('Busca Colaboradores').all().map(i => i.json).filter(c => c.nome);
  const colabMap = new Map();
  for (const c of colabRows) colabMap.set(c.nome, c);
  colaboradoresArray = Array.from(colabMap.values());
} catch(e) {}

// 6. DADOS DA MENSAGEM
let _vM;
try { _vM = $('Verifica Menção').first().json; if (!_vM.chatId) _vM = null; } catch(e) {}
if (!_vM) try { _vM = $('Formata Transcrição').first().json; } catch(e) { _vM = {}; }
const chatId = _vM.chatId || '';
const textMessage = _vM.textMessage || '';

const now = new Date();
const brt = new Date(now.toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));
const dia = brt.getDate().toString().padStart(2,'0');
const mes = (brt.getMonth()+1).toString().padStart(2,'0');
const ano = brt.getFullYear();
const today = `${ano}-${mes}-${dia}`;
const msgLower = textMessage.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

// 7. MONTAGEM DOS POPs
const isListingPops = msgLower.includes('pop') || msgLower.includes('procedimento') || msgLower.includes('quais pops') || msgLower.includes('lista');
let pops = '';

// POPs "LEIA SEMPRE" — aparecem em TODAS as respostas
if (leiasSemprePops.length > 0) {
  pops += '📌 LEIA ANTES DE RESPONDER:\n\n';
  for (const pop of leiasSemprePops) {
    pops += '=== ' + pop.titulo + ' ===\n' + pop.conteudo + '\n\n';
  }
  pops += '---\n\n';
}

if (relevantNonClientPops.length > 0 && !isListingPops) {
  for (const pop of relevantNonClientPops) {
    pops += '=== ' + pop.titulo + ' (' + (pop.categoria || 'Geral') + ') ===\n' + pop.conteudo + '\n\n';
  }
  const titlesWithoutContent = allNonClientTitles
    .filter(p => !relevantNonClientPops.find(r => r.titulo === p.titulo) && !leiasSemprePops.find(r => r.titulo === p.titulo))
    .map(p => `- ${p.titulo} (${p.categoria || 'Geral'})`).join('\n');
  if (titlesWithoutContent) {
    pops += '\n📚 OUTROS POPs DISPONÍVEIS:\n' + titlesWithoutContent;
  }
} else {
  const titulos = allNonClientTitles
    .filter(p => !leiasSemprePops.find(r => r.titulo === p.titulo))
    .map(p => `- ${p.titulo} (${p.categoria || 'Geral'})`).join('\n');
  if (titulos) pops += 'POPs disponíveis:\n' + titulos;
}

const popsUsados = (relevantNonClientPops.length > 0 && !isListingPops)
  ? relevantNonClientPops.map(p => p.titulo).join(', ')
  : '';

// 8. CLIENTES
let totalClientes = 0;
const clientesEncontrados = [];
try {
  const cliRows = $('Busca Clientes').all().map(i => i.json);
  for (const c of cliRows) {
    if (c.cod === 'TOTAL') { totalClientes = parseInt(c.nome) || 0; }
    else if (c.cod && c.nome) { clientesEncontrados.push(c.cod + ' - ' + c.nome); }
  }
} catch(e) {}

const clienteInfo = clientesEncontrados.length > 0
  ? 'CLIENTES ENCONTRADOS NA BUSCA: ' + clientesEncontrados.join(' | ') + ' (Total na base: ' + totalClientes + ')'
  : 'Base de clientes ativa com ' + totalClientes + ' clientes cadastrados. Quando mencionar um nome, os resultados aparecem automaticamente.';

const colaboradoresStr = colaboradoresArray.length > 0
  ? 'COLABORADORES DA EQUIPE:\n' + colaboradoresArray.map(c =>
      `- ${c.nome}${c.cargo ? ' (' + c.cargo + ')' : ''}${c.funcoes ? ': ' + c.funcoes : ''}`
    ).join('\n')
  : '';

// 9. MONTAGEM FINAL DO SYSTEM CONTENT
let systemContent;
if (systemPromptTemplate && systemPromptTemplate !== '__RESET_TO_DEFAULT__') {
  systemContent = systemPromptTemplate
    .replace(/\{\{DATA\}\}/g, `${dia}/${mes}/${ano}`)
    .replace(/\{\{ANO\}\}/g, String(ano))
    .replace(/\{\{TODAY\}\}/g, today)
    .replace(/\{\{COLABORADORES\}\}/g, colaboradoresStr)
    .replace(/\{\{CLIENTES\}\}/g, clienteInfo)
    .replace(/\{\{POPS\}\}/g, pops)
    .replace(/\{\{HISTORICO\}\}/g, historicoSection)
    .replace(/\{\{REGRAS\}\}/g, rulesPrompt);
  systemContent = rulesPrompt + chamadosContext + '\n' + systemContent;
} else {
  systemContent = rulesPrompt
    + '\nVocê é o assistente interno da Zazz Internet, provedor de fibra óptica em Lunardelli-PR. Seu nome é Maluco da IA 👽🍀.\n\n'
    + 'DATA ATUAL: ' + dia + '/' + mes + '/' + ano + ' (' + today + '). ANO ATUAL: ' + ano + '.\n\n'
    + 'FORMATAÇÃO OBRIGATÓRIA (WhatsApp):\n'
    + '- Negrito: *texto* (UM asterisco)\n'
    + '- Itálico: _texto_\n'
    + '- PROIBIDO: ** ## ### blocos de código\n'
    + '- Passos: use 1. 2. 3.\n\n'
    + colaboradoresStr + '\n\n'
    + clienteInfo + '\n\n'
    + 'POPs DA EMPRESA:\n' + pops
    + historicoSection
    + chamadosContext;
}

// 10. LIMITE DE SEGURANÇA
if (systemContent.length > 80000) {
  systemContent = systemContent.substring(0, 80000) + '\n[...truncado por limite de memória...]';
}

// 11. TRAVA FINAL
if (!textMessage) return [];

return [{
  json: {
    chatId,
    remetente,
    mensagemUsuario: textMessage,
    popsUsados,
    chamadosCarregados: chamadosContext.length > 0 ? 'SIM (' + chamadosContext.length + ' chars)' : 'NAO',
    claudeBody: {
      model: "claude-haiku-4-5-20251001",
      max_tokens: 4096,
      system: systemContent,
      messages: [
        ...redisHistory.slice(-20),
        { role: "user", content: textMessage }
      ]
    }
  }
}];

const response = $input.first().json;

// Tokens
const tokensInput = response.usage?.input_tokens || 0;
const tokensOutput = response.usage?.output_tokens || 0;

// Erro da API
if (response.error || !response.content) {
  let _vME; try { _vME = $('Verifica Menção').first().json; } catch(e) { _vME = {}; }
  const errMsg = response.error?.message || response.message || JSON.stringify(response).substring(0,300);
  return [{ json: {
    chatId: _vME.chatId || '',
    message: '❌ Tive um probleminha técnico, tenta de novo em instantes 🍀',
    hasNotion: false, isError: true,
    errorMsg: errMsg,
    mensagemUsuario: _vME.textMessage || '',
    novoHistorico: '[]', tokensInput: 0, tokensOutput: 0, popsUsados: '', remetente: ''
  }}];
}

const fullText = response.content[0].text;
let _vM; try { _vM = $('Verifica Menção').first().json; if (!_vM.chatId) _vM = null; } catch(e) {}
if (!_vM) try { _vM = $('Formata Transcrição').first().json; } catch(e) { _vM = {}; }
const chatId = _vM.chatId || '';

const responsavelMap = {
  'junior': '60f09078-44d0-4a2e-9b56-b8917fdfd87e',
  'franquelin': '826e94f5-aed7-4421-ae97-deee67c6f6af',
  'luiz': 'f6b0bba1-309e-46a9-9b37-d5a18c150a16',
  'negos': '7630461f-d189-4b51-a139-28043faae78f',
  'nego': '7630461f-d189-4b51-a139-28043faae78f',
  'gester': '7630461f-d189-4b51-a139-28043faae78f',
  'victor': 'f22c8443-ce89-49d6-94f4-3c6d391cf715',
  'vitor': 'f22c8443-ce89-49d6-94f4-3c6d391cf715',
  'russo': '60f09078-44d0-4a2e-9b56-b8917fdfd87e'
};

let notionData = null;
let whatsappMessage = fullText;
let notionBody = null;

if (fullText.includes('|||NOTION|||')) {
  const notionMatch = fullText.match(/\|\|\|NOTION\|\|\|([\s\S]*?)\|\|\|FIM\|\|\|/);
  if (notionMatch) {
    try {
      notionData = JSON.parse(notionMatch[1].trim());

      const respNome = (notionData.responsavel || 'franquelin, victor').toLowerCase()
        .normalize('NFD').replace(/[\u0300-\u036f]/g, '');
      let respPeople = [];
      let addedIds = [];
      for (const [key, id] of Object.entries(responsavelMap)) {
        if (respNome.includes(key) && !addedIds.includes(id)) {
          respPeople.push({"id": id});
          addedIds.push(id);
        }
      }
      if (respPeople.length === 0) {
        respPeople = [{"id": "826e94f5-aed7-4421-ae97-deee67c6f6af"}];
      }

      notionBody = {
        "parent": {"database_id": "d54e5911e8af43dfaed8f2893e59f6ef"},
        "properties": {
          "Descrição": {"title": [{"text": {"content": notionData.descricao || ""}}]},
          "Cliente": {"rich_text": [{"text": {"content": notionData.cliente || ""}}]},
          "status": {"select": {"name": notionData.status || "Parado"}},
          "Data": {"date": {"start": notionData.data}},
          "Tipo": {"multi_select": [{"name": notionData.tipo || "Internet"}]},
          "Entrega": {"date": {"start": notionData.entrega || notionData.data}},
          "Obs": {"rich_text": [{"text": {"content": notionData.obs || ""}}]},
          "Fone": {"phone_number": notionData.fone || null},
          "Valor": {"number": 0},
          "Atendente": {"people": [{"id": "325d872b-594c-81fe-a524-00029761e655"}]},
          "Responsável": {"people": respPeople}
        }
      };

    } catch(e) {
      notionData = null;
    }
    whatsappMessage = fullText.replace(/\|\|\|NOTION\|\|\|[\s\S]*?\|\|\|FIM\|\|\|/, '').trim();
  }
}

// Monta histórico atualizado para Redis
let _prevHist = [];
try { const rv2 = $('Busca Histórico Redis').first().json?.value; if(rv2) _prevHist = JSON.parse(rv2); } catch(e) {}
let _msgUsr = ''; try { _msgUsr = $('Verifica Menção').first().json?.textMessage || $('Formata Transcrição').first().json?.textMessage || ''; } catch(e) {}
let _popsUsd = ''; try { _popsUsd = $('Monta Prompt').first().json?.popsUsados || ''; } catch(e) {}
let _rem = ''; try { _rem = $('Monta Prompt').first().json?.remetente || ''; } catch(e) {}
const novoHistorico = JSON.stringify([..._prevHist, {role:'user',content:_msgUsr.substring(0,2000)}, {role:'assistant',content:whatsappMessage.substring(0,4000)}].slice(-20));

return [{
  json: {
    chatId: chatId,
    message: whatsappMessage,
    notionData: notionData,
    notionBody: notionBody,
    hasNotion: notionBody !== null,
    isError: false,
    novoHistorico: novoHistorico,
    mensagemUsuario: _msgUsr,
    remetente: _rem,
    popsUsados: _popsUsd,
    tokensInput: tokensInput,
    tokensOutput: tokensOutput
  }
}];

